## HTTP-Specific Patterns
Document patterns for HTTP usage:
```rust
// Reading HTTP request line-by-line
async fn read_http_request(cx: &Cx<'_>, stream: &TcpStream) -> Outcome<Request, ParseError> {
    let mut reader = BufReader::new(stream.split().0);

    // Read request line
    let mut line = String::new();
    reader.read_line(cx, &mut line).await?;
    let request_line = parse_request_line(&line)?;

    // Read headers
    let mut headers = HeaderMap::new();
    loop {
        line.clear();
        reader.read_line(cx, &mut line).await?;
        if line == "\r\n" { break; }
        let (name, value) = parse_header(&line)?;
        headers.insert(name, value);
    }

    // Read body based on Content-Length
    // ...
}
```

